package main

import (
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"

	"github.com/go-redis/redis/v8"
	"github.com/gorilla/mux"
)

var uploadDir = "./public"
var redisClient *redis.Client

func init() {
	// Initialize Redis client if needed
	redisClient = redis.NewClient(&redis.Options{
		Addr:     "localhost:6379",
		Password: "", // no password set
		DB:       0,  // use default DB
	})
}

func uploadFile(w http.ResponseWriter, r *http.Request) {
	r.ParseMultipartForm(10 << 20) // max upload size: 10MB
	file, header, err := r.FormFile("file")
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}
	defer file.Close()

	ext := strings.ToLower(strings.Split(header.Filename, ".")[len(strings.Split(header.Filename, "."))-1])
	allowedTypes := []string{"jpg", "jpeg", "png", "gif", "doc", "docx", "pdf", "zip", "rar"}
	if !contains(allowedTypes, ext) {
		http.Error(w, "Unsupported file type.", http.StatusBadRequest)
		return
	}

	filePath := filepath.Join(uploadDir, header.Filename)
	out, err := os.Create(filePath)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	defer out.Close()

	_, err = io.Copy(out, file)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	fmt.Fprintf(w, "File uploaded successfully: %s\n", header.Filename)
	storeInRedis(filePath)
}

func contains(slice []string, item string) bool {
	for _, a := range slice {
		if a == item {
			return true
		}
	}
	return false
}

func storeInRedis(filePath string) {
	err := redisClient.Set(context.Background(), filePath, filePath, 0).Err()
	if err != nil {
		log.Fatalf("Error storing file path in Redis: %v", err)
	}
}

func main() {
	router := mux.NewRouter()
	router.HandleFunc("/upload", uploadFile).Methods("POST")
	http.ListenAndServe(":8080", router)
}